const EPS=1e-9;export const CURRENCY_UNITS=Object.freeze([{value:100,label:"$100"},{value:50,label:"$50"},{value:20,label:"$20"},{value:10,label:"$10"},{value:5,label:"$5"},{value:2,label:"$2"},{value:1,label:"$1"},{value:.25,label:"Quarter"},{value:.1,label:"Dime"},{value:.05,label:"Nickel"},{value:.01,label:"Penny"}]);export function parseInput(e){if(!e||"string"!=typeof e)return null;const l=e.trim();let a;if(l.includes(" "))a=l.split(/\s+/);else if(l.includes("/"))a=l.split("/");else if(l.includes("+"))a=l.split("+");else{if(!l.includes(","))return null;a=l.split(",")}if(a.length<2)return null;const t=parseFloat(a[0]),n=parseFloat(a[1]);return isNaN(t)||isNaN(n)||t<0||n<0?null:{price:Math.round(100*t)/100,paid:Math.round(100*n)/100}}export function greedy(e,l=CURRENCY_UNITS,a=1/0){let t=e;const n=[];for(const e of l){if(t<e.value-EPS)continue;const l=Math.floor(t/e.value+EPS),i=Math.min(l,a);if(i>0&&(n.push({value:e.value,label:e.label,count:i}),t=+(t-e.value*i).toFixed(2)),t<EPS)break}return{items:n,remaining:t>EPS?t:0}}const DESCRIPTIONS={optimal:"Uses the fewest pieces possible. Best for fast cash transactions — count and hand over quickly.",balanced:"Spreads change across more denominations so you don't run out of small bills. Great for everyday wallet use.",practical:"Avoids tiny coins (pennies & nickels). Ideal when the receiver prefers fewer small coins in their pocket."};export function calculate(e,l){const a=+(+e).toFixed(2),t=+(+l).toFixed(2);if(isNaN(a)||isNaN(t)||a<0||t<0)return{status:"invalid",balance:0,plans:[]};const n=+(t-a).toFixed(2);if(Math.abs(n)<EPS)return{status:"exact",balance:0,plans:[]};if(n<0)return{status:"short",balance:n,plans:[]};const i=[{id:"optimal",name:"Optimal Plan",cap:1/0,filter:null},{id:"balanced",name:"Balanced Plan",cap:3,filter:null},{id:"practical",name:"Practical Plan",cap:1/0,filter:e=>e.value>=.1}].map(e=>{const l=e.filter?CURRENCY_UNITS.filter(e.filter):CURRENCY_UNITS;let a=greedy(n,l,e.cap);if("practical"===e.id&&a.remaining>EPS){a=greedy(n,CURRENCY_UNITS)}return{id:e.id,name:e.name,totalCount:a.items.reduce((e,l)=>e+l.count,0),typeCount:a.items.length,units:a.items.map(e=>({value:e.value,label:e.label,count:e.count})),desc:DESCRIPTIONS[e.id]}});return{status:"settled",balance:n,plans:i}}